&lt;li&gt;&lt;span class=&quot; author-d-1gg9uz65z1iz85zgdz68zmqkz84zo2qoxvz75zfxfz86zgwmhwz74zz65zjk8jz88zgz84zwz68zioz65zz65zz76zz81zbwf&quot;&gt;Experience building web applications using&lt;/span&gt;&lt;span class=&quot;highlight author-d-1gg9uz65z1iz85zgdz68zmqkz84zo2qoxvz75zfxfz86zgwmhwz74zz65zjk8jz88zgz84zwz68zioz65zz65zz76zz81zbwf&quot; data-highlight-color=&quot;#D8C3FF&quot;&gt; TypeScript and React&lt;/span&gt;&lt;span class=&quot; author-d-1gg9uz65z1iz85zgdz68zmqkz84zo2qoxvz75zfxfz86zgwmhwz74zz65zjk8jz88zgz84zwz68zioz65zz65zz76zz81zbwf&quot;&gt;.&lt;/span&gt;&lt;/li&gt;
