&lt;p&gt;&lt;span class=&quot; author-d-1gg9uz65z1iz85zgdz68zmqkz84zo2qowz82z5hz72z4erz72zz90z8z89z44dz122zjz69zdz76zaz77zuz80z2z84zvz76zgxz74zs&quot;&gt;Familiarity with tools and languages used &lt;/span&gt;&lt;span class=&quot; author-d-1gg9uz65z1iz85zgdz68zmqkz84zo2qowz81zz86z2z74z6auz77zz85zz76ztjz80zz68z4x081pz122zz65zbz71zz71zqz84zwfmz86z&quot;&gt;on the&lt;/span&gt;&lt;span class=&quot; author-d-1gg9uz65z1iz85zgdz68zmqkz84zo2qowz82z5hz72z4erz72zz90z8z89z44dz122zjz69zdz76zaz77zuz80z2z84zvz76zgxz74zs&quot;&gt; DocSend&lt;/span&gt;&lt;span class=&quot; author-d-1gg9uz65z1iz85zgdz68zmqkz84zo2qowz81zz86z2z74z6auz77zz85zz76ztjz80zz68z4x081pz122zz65zbz71zz71zqz84zwfmz86z&quot;&gt; Engineering team. This includes &lt;/span&gt;&lt;span class=&quot; author-d-1gg9uz65z1iz85zgdz68zmqkz84zo2qowz82z5hz72z4erz72zz90z8z89z44dz122zjz69zdz76zaz77zuz80z2z84zvz76zgxz74zs&quot;&gt;Typescript, GraphQL, HAML, PostgreSQL&lt;/span&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 data-usually-unique-id=&quot;044234883370604133046166&quot;&gt;&lt;span class=&quot; author-d-1gg9uz65z1iz85zgdz68zmqkz84zo2qowz81zqz90zkz74zz76zeez80zz68zz89zz88zvqz86zuxlz73zexxz80zz73z6d6z72zz79zsz77z&quot;&gt;Compensation&lt;/span&gt;&lt;/h2&gt;&lt;div class=&quot;content-pay-transparency&quot;&gt;&lt;div class=&quot;pay-input&quot;&gt;&lt;div class=&quot;description&quot;&gt;&lt;p&gt;&lt;span style=&quot;font-size: 16px;&quot;&gt;US Zone 1&lt;/span&gt;&lt;/p&gt;
